{"title":"KCP Log Rejection Count","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega-lite/v4.json",
  "data": {
    name: kibana_data_load
    "url": {
      "index": "cls-rejected-*"
      "body": {
        "query": {
          bool: {
              must: [
                %dashboard_context-must_clause%
                { match: { "index_prefix": "logs-json-kyma" } }
              ]
              filter: [
                %dashboard_context-filter_clause%
                {
                  range: {
                    @timestamp: {
                      gte: {
                        %timefilter%: min
                      }
                      lte: {
                        %timefilter%: max
                      }
                    }
                  }
                }
              ]
              must_not: [
                %dashboard_context-must_not_clause%
              ]
            }
        }
        "size": 0
      }
    }
  },
  "transform": [
    {
      "calculate": "datum.hits.total > 0 ? datum.hits.total : 0",
      "as": "count"
    }
    {
      "calculate": "'Total Rejections'",
      "as": "title"
    }
  ],
  "layer": [
    {
      "encoding": {
        "text": {
          "field": "count"
        }
        "color": {
          "condition": {"test": "datum.hits.total < 1", "value": "#54b399"}
          "value": "#e7664c"
        }
      },
      "mark": {
        "type": "text",
        "fontSize": 75,
        "fontWeight": "bold"
        "yOffset": 33
        "font": "Inter UI, -apple-system, BlinkMacSystemFont, Segoe UI, Helvetica, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol"
      },
    },
    {
      "encoding": {
        "text": {
          "field": "title"
        }
        "color": {
          "value": "#9D9D9D"
        }
      },
      "mark": {
        "type": "text",
        "fontSize": 40,
        "yOffset": -33
        "font": "Inter UI, -apple-system, BlinkMacSystemFont, Segoe UI, Helvetica, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol"
      },
    }
  ]
  "config": {
    "view": {
      "stroke": "transparent"
    }
  }
}"}}

